package net.guides.springboot.todomanagement.controller;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.List;

import javax.validation.Valid;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.propertyeditors.CustomDateEditor;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Controller;
import org.springframework.ui.ModelMap;
import org.springframework.validation.BindingResult;
import org.springframework.web.bind.WebDataBinder;
import org.springframework.web.bind.annotation.InitBinder;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestMethod;
import org.springframework.web.bind.annotation.RequestParam;

import net.guides.springboot.todomanagement.model.Todo;
import net.guides.springboot.todomanagement.service.ITodoService;
import net.guides.springboot.todomanagement.model.User;
import net.guides.springboot.todomanagement.service.UserService;
import net.guides.springboot.todomanagement.model.Priority;
import net.guides.springboot.todomanagement.model.Status;

import java.time.LocalDate;
import java.time.ZoneId;
import java.time.temporal.ChronoUnit;
import java.util.HashMap;
import java.util.Map;
import java.util.stream.Collectors;

@Controller
public class TodoController {

	@Autowired
	private ITodoService todoService;

	@Autowired
	private UserService userService;

	@InitBinder
	public void initBinder(WebDataBinder binder) {
		// Date - dd/MM/yyyy
		SimpleDateFormat dateFormat = new SimpleDateFormat("dd/MM/yyyy");
		binder.registerCustomEditor(Date.class, new CustomDateEditor(dateFormat, false));
	}

	@RequestMapping(value = "/list-todos", method = RequestMethod.GET)
	public String showTodos(@RequestParam(required = false) String search,
							@RequestParam(required = false) String statusFilter,
							@RequestParam(required = false) String priorityFilter,
							ModelMap model) {
		User user = getLoggedInUser(model);
		Long userId = (user != null) ? user.getId() : null;
		// fetch all todos for user
		java.util.List<Todo> todos = (userId != null) ? todoService.getTodosByUserId(userId) : java.util.Collections.emptyList();

		// apply status and priority filters on the already-fetched list so multiple filters combine
		if (statusFilter != null && !statusFilter.isEmpty()) {
			try {
				Status status = Status.valueOf(statusFilter);
				todos = todos.stream()
						.filter(t -> t.getStatus() == status)
						.collect(Collectors.toList());
			} catch (IllegalArgumentException e) {
				// invalid status, ignore
			}
		}

		if (priorityFilter != null && !priorityFilter.isEmpty()) {
			try {
				Priority priority = Priority.valueOf(priorityFilter);
				todos = todos.stream()
						.filter(t -> t.getPriority() == priority)
						.collect(Collectors.toList());
			} catch (IllegalArgumentException e) {
				// invalid priority, ignore
			}
		}

		// filter by search (description) if provided
		if (search != null && !search.trim().isEmpty()) {
			String q = search.trim().toLowerCase();
			todos = todos.stream()
					.filter(t -> t.getDescription() != null && t.getDescription().toLowerCase().contains(q))
					.collect(Collectors.toList());
		}

		// build map todoId -> daysUntilDue (targetDate - today)
		Map<Long, Long> daysLeftMap = new HashMap<>();
		for (Todo t : todos) {
			if (t.getTargetDate() != null) {
				LocalDate target = t.getTargetDate().toInstant().atZone(ZoneId.systemDefault()).toLocalDate();
				long daysLeft = ChronoUnit.DAYS.between(LocalDate.now(), target);
				daysLeftMap.put(t.getId(), daysLeft);
			} else {
				daysLeftMap.put(t.getId(), null);
			}
		}

		model.put("todos", todos);
		model.put("search", search);
		model.put("statusFilter", statusFilter);
		model.put("priorityFilter", priorityFilter);
		model.put("statuses", Status.values());
		model.put("priorities", Priority.values());
		model.put("daysLeftMap", daysLeftMap);
		return "list-todos";
	}

	private User getLoggedInUser(ModelMap model) {
		org.springframework.security.core.Authentication auth = SecurityContextHolder.getContext().getAuthentication();
		if (auth == null) {
			return null;
		}
		Object principal = auth.getPrincipal();
		String username = null;
		if (principal instanceof UserDetails) {
			username = ((UserDetails) principal).getUsername();
		} else {
			username = (principal != null) ? principal.toString() : null;
		}
		if (username == null) return null;
		return userService.findByUsername(username);
	}

	@RequestMapping(value = "/add-todo", method = RequestMethod.GET)
	public String showAddTodoPage(ModelMap model) {
		model.addAttribute("todo", new Todo());
		return "todo";
	}

	@RequestMapping(value = "/delete-todo", method = RequestMethod.GET)
	public String deleteTodo(@RequestParam long id) {
		todoService.deleteTodo(id);
		// service.deleteTodo(id);
		return "redirect:/list-todos";
	}

	@RequestMapping(value = "/update-todo", method = RequestMethod.GET)
	public String showUpdateTodoPage(@RequestParam long id, ModelMap model) {
		Todo todo = todoService.getTodoById(id)
				.orElseThrow(() -> new IllegalArgumentException("Invalid todo id: " + id));
		model.put("todo", todo);
		return "todo";
	}

	@RequestMapping(value = "/update-todo", method = RequestMethod.POST)
	public String updateTodo(ModelMap model, @Valid Todo todo, BindingResult result) {

		if (result.hasErrors()) {
			return "todo";
		}

		User user = getLoggedInUser(model);
		if (user != null) todo.setUser(user);
		todoService.updateTodo(todo);
		return "redirect:/list-todos";
	}

	@RequestMapping(value = "/add-todo", method = RequestMethod.POST)
	public String addTodo(ModelMap model, @Valid Todo todo, BindingResult result) {

		if (result.hasErrors()) {
			return "todo";
		}

		User user = getLoggedInUser(model);
		if (user != null) todo.setUser(user);
		todoService.saveTodo(todo);
		return "redirect:/list-todos";
	}

	@RequestMapping(value = "/update-todo-status", method = RequestMethod.GET)
	public String updateTodoStatus(@RequestParam long id, @RequestParam String status) {
		try {
			Status s = Status.valueOf(status);
			todoService.updateTodoStatus(id, s);
		} catch (IllegalArgumentException e) {
			// ignore invalid status
		}
		return "redirect:/list-todos";
	}
}

package net.guides.springboot.todomanagement.controller;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.List;

import javax.validation.Valid;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.propertyeditors.CustomDateEditor;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Controller;
import org.springframework.ui.ModelMap;
import org.springframework.validation.BindingResult;
import org.springframework.web.bind.WebDataBinder;
import org.springframework.web.bind.annotation.InitBinder;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestMethod;
import org.springframework.web.bind.annotation.RequestParam;

import net.guides.springboot.todomanagement.model.Todo;
import net.guides.springboot.todomanagement.service.ITodoService;
import net.guides.springboot.todomanagement.model.User;
import net.guides.springboot.todomanagement.service.UserService;
import net.guides.springboot.todomanagement.model.Priority;
import net.guides.springboot.todomanagement.model.Status;

import java.time.LocalDate;
import java.time.ZoneId;
import java.time.temporal.ChronoUnit;
import java.util.HashMap;
import java.util.Map;
import java.util.stream.Collectors;

@Controller
public class TodoController {

	@Autowired
	private ITodoService todoService;

	@Autowired
	private UserService userService;

	@Autowired
	private net.guides.springboot.todomanagement.service.TagService tagService;

	@InitBinder
	public void initBinder(WebDataBinder binder) {
		// Date - dd/MM/yyyy
		SimpleDateFormat dateFormat = new SimpleDateFormat("dd/MM/yyyy");
		binder.registerCustomEditor(Date.class, new CustomDateEditor(dateFormat, false));
	}

	@RequestMapping(value = "/list-todos", method = RequestMethod.GET)
	public String showTodos(@RequestParam(required = false) String search,
							@RequestParam(required = false) String statusFilter,
							@RequestParam(required = false) String priorityFilter,
							@RequestParam(required = false) String tagFilter,
							ModelMap model) {
		User user = getLoggedInUser(model);
		Long userId = (user != null) ? user.getId() : null;
		// fetch all todos for user
		java.util.List<Todo> todos = (userId != null) ? todoService.getTodosByUserId(userId) : java.util.Collections.emptyList();

		// apply status and priority filters on the already-fetched list so multiple filters combine
		if (statusFilter != null && !statusFilter.isEmpty()) {
			try {
				Status status = Status.valueOf(statusFilter);
				todos = todos.stream()
						.filter(t -> t.getStatus() == status)
						.collect(Collectors.toList());
			} catch (IllegalArgumentException e) {
				// invalid status, ignore
			}
		}

		if (priorityFilter != null && !priorityFilter.isEmpty()) {
			try {
				Priority priority = Priority.valueOf(priorityFilter);
				todos = todos.stream()
						.filter(t -> t.getPriority() == priority)
						.collect(Collectors.toList());
			} catch (IllegalArgumentException e) {
				// invalid priority, ignore
			}
		}

		// filter by tag name (single tag) if provided
		if (tagFilter != null && !tagFilter.isEmpty()) {
			String tf = tagFilter.trim();
			todos = todos.stream()
					.filter(t -> t.getTags() != null && t.getTags().stream().anyMatch(tag -> tf.equals(tag.getName())))
					.collect(Collectors.toList());
		}

		// filter by search (description) if provided
		if (search != null && !search.trim().isEmpty()) {
			String q = search.trim().toLowerCase();
			todos = todos.stream()
					.filter(t -> t.getDescription() != null && t.getDescription().toLowerCase().contains(q))
					.collect(Collectors.toList());
		}

		// build map todoId -> daysUntilDue (targetDate - today)
		Map<Long, Long> daysLeftMap = new HashMap<>();
		for (Todo t : todos) {
			if (t.getTargetDate() != null) {
				LocalDate target = t.getTargetDate().toInstant().atZone(ZoneId.systemDefault()).toLocalDate();
				long daysLeft = ChronoUnit.DAYS.between(LocalDate.now(), target);
				daysLeftMap.put(t.getId(), daysLeft);
			} else {
				daysLeftMap.put(t.getId(), null);
			}
		}

		model.put("todos", todos);
		model.put("search", search);
		model.put("statusFilter", statusFilter);
		model.put("priorityFilter", priorityFilter);
		model.put("statuses", Status.values());
		model.put("priorities", Priority.values());
		model.put("allTags", tagService.findAll());
		model.put("daysLeftMap", daysLeftMap);
		return "list-todos";
	}

	private User getLoggedInUser(ModelMap model) {
		org.springframework.security.core.Authentication auth = SecurityContextHolder.getContext().getAuthentication();
		if (auth == null) {
			return null;
		}
		Object principal = auth.getPrincipal();
		String username = null;
		if (principal instanceof UserDetails) {
			username = ((UserDetails) principal).getUsername();
		} else {
			username = (principal != null) ? principal.toString() : null;
		}
		if (username == null) return null;
		return userService.findByUsername(username);
	}

	@RequestMapping(value = "/add-todo", method = RequestMethod.GET)
	public String showAddTodoPage(ModelMap model) {
		model.addAttribute("todo", new Todo());
		model.put("tagNames", "");
		model.put("allTags", tagService.findAll());
		return "todo";
	}

	@RequestMapping(value = "/delete-todo", method = RequestMethod.GET)
	public String deleteTodo(@RequestParam long id) {
		todoService.deleteTodo(id);
		// service.deleteTodo(id);
		return "redirect:/list-todos";
	}

	@RequestMapping(value = "/update-todo", method = RequestMethod.GET)
	public String showUpdateTodoPage(@RequestParam long id, ModelMap model) {
		Todo todo = todoService.getTodoById(id)
				.orElseThrow(() -> new IllegalArgumentException("Invalid todo id: " + id));
		model.put("todo", todo);
		// prepare comma-separated tag names
		if (todo.getTags() != null && !todo.getTags().isEmpty()) {
			String tagNames = todo.getTags().stream().map(t -> t.getName()).collect(Collectors.joining(", "));
			model.put("tagNames", tagNames);
		} else {
			model.put("tagNames", "");
		}
		model.put("allTags", tagService.findAll());
		return "todo";
	}

	@RequestMapping(value = "/update-todo", method = RequestMethod.POST)
	public String updateTodo(ModelMap model, @Valid Todo todo, BindingResult result) {

		if (result.hasErrors()) {
			return "todo";
		}
		User user = getLoggedInUser(model);
		if (user != null) todo.setUser(user);

		// tags handled via request param 'tagNames' (comma separated)
		// retrieve raw param from model or request
		String tagNames = (String) model.get("tagNames");
		// when using Spring form binding, the param may not be in model; try request
		if (tagNames == null) {
			tagNames = org.springframework.web.context.request.RequestContextHolder.currentRequestAttributes()
					.getAttribute("tagNames", org.springframework.web.context.request.RequestAttributes.SCOPE_REQUEST) != null
					? org.springframework.web.context.request.RequestContextHolder.currentRequestAttributes()
							.getAttribute("tagNames", org.springframework.web.context.request.RequestAttributes.SCOPE_REQUEST).toString()
					: null;
		}
		// If tagNames still null, it will be empty
		if (tagNames != null) {
			String[] parts = tagNames.split(",");
			java.util.Set<net.guides.springboot.todomanagement.model.Tag> tags = new java.util.HashSet<>();
			for (String p : parts) {
				String n = p.trim();
				if (n.isEmpty()) continue;
				net.guides.springboot.todomanagement.model.Tag t = tagService.createIfNotExists(n);
				if (t != null) tags.add(t);
			}
			todo.setTags(tags);
		}

		todoService.updateTodo(todo);
		return "redirect:/list-todos";
	}

	@RequestMapping(value = "/add-todo", method = RequestMethod.POST)
	public String addTodo(ModelMap model, @Valid Todo todo, BindingResult result) {

		if (result.hasErrors()) {
			return "todo";
		}

		User user = getLoggedInUser(model);
		if (user != null) todo.setUser(user);
		todoService.saveTodo(todo);
		return "redirect:/list-todos";
	}

	@RequestMapping(value = "/update-todo-status", method = RequestMethod.GET)
	public String updateTodoStatus(@RequestParam long id, @RequestParam String status) {
		try {
			Status s = Status.valueOf(status);
			todoService.updateTodoStatus(id, s);
		} catch (IllegalArgumentException e) {
			// ignore invalid status
		}
		return "redirect:/list-todos";
	}
}

package net.guides.springboot.todomanagement.model;

import javax.persistence.Entity;
import javax.persistence.GeneratedValue;
import javax.persistence.GenerationType;
import javax.persistence.Id;
import javax.persistence.Table;
import javax.persistence.Column;

@Entity
@Table(name = "tags")
public class Tag {

    @Id
    @GeneratedValue(strategy = GenerationType.AUTO)
    private Long id;

    @Column(unique = true, nullable = false)
    private String name;

    public Tag() {}

    public Tag(String name) {
        this.name = name;
    }

    public Long getId() {
        return id;
    }

    public void setId(Long id) {
        this.id = id;
    }

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }

    @Override
    public String toString() {
        return name;
    }
}

package net.guides.springboot.todomanagement.model;

import java.util.Date;

import javax.persistence.Entity;
import javax.persistence.GeneratedValue;
import javax.persistence.GenerationType;
import javax.persistence.Id;
import javax.persistence.JoinColumn;
import javax.persistence.ManyToOne;
import javax.persistence.FetchType;
import javax.persistence.Table;
import javax.validation.constraints.Size;

import net.guides.springboot.todomanagement.model.User;

@Entity
@Table(name = "todos")
public class Todo {

	@Id
	@GeneratedValue(strategy = GenerationType.AUTO)
	private long id;

	@ManyToOne(fetch = FetchType.LAZY)
	@JoinColumn(name = "user_id", nullable = true)
	private User user;

	@Size(min = 10, message = "Enter at least 10 Characters...")
	private String description;

	private Date targetDate;

	private Priority priority = Priority.MEDIUM;

	private Status status = Status.TODO;

	public Todo() {
		super();
	}

	public Todo(User user, String desc, Date targetDate) {
		super();
		this.user = user;
		this.description = desc;
		this.targetDate = targetDate;
	}

	public long getId() {
		return id;
	}

	public void setId(long id) {
		this.id = id;
	}

	public User getUser() {
		return user;
	}

	public void setUser(User user) {
		this.user = user;
	}

	public String getDescription() {
		return description;
	}

	public void setDescription(String description) {
		this.description = description;
	}

	public Date getTargetDate() {
		return targetDate;
	}

	public void setTargetDate(Date targetDate) {
		this.targetDate = targetDate;
	}

	public Priority getPriority() {
		return priority;
	}

	public void setPriority(Priority priority) {
		this.priority = priority;
	}

	public Status getStatus() {
		return status;
	}

	public void setStatus(Status status) {
		this.status = status;
	}
}

package net.guides.springboot.todomanagement.model;

import java.util.Date;
import java.util.Set;
import java.util.HashSet;

import javax.persistence.Entity;
import javax.persistence.GeneratedValue;
import javax.persistence.GenerationType;
import javax.persistence.Id;
import javax.persistence.JoinColumn;
import javax.persistence.ManyToOne;
import javax.persistence.ManyToMany;
import javax.persistence.JoinTable;
import javax.persistence.JoinColumn;
import javax.persistence.FetchType;
import javax.persistence.Table;
import javax.validation.constraints.Size;

import net.guides.springboot.todomanagement.model.User;

@Entity
@Table(name = "todos")
public class Todo {

	@Id
	@GeneratedValue(strategy = GenerationType.AUTO)
	private long id;

	@ManyToOne(fetch = FetchType.LAZY)
	@JoinColumn(name = "user_id", nullable = true)
	private User user;

	@Size(min = 10, message = "Enter at least 10 Characters...")
	private String description;

	private Date targetDate;

	private Priority priority = Priority.MEDIUM;

	private Status status = Status.TODO;

	@ManyToMany
	@JoinTable(name = "todo_tags",
			joinColumns = @JoinColumn(name = "todo_id"),
			inverseJoinColumns = @JoinColumn(name = "tag_id"))
	private Set<Tag> tags = new HashSet<>();

	public Todo() {
		super();
	}

	public Todo(User user, String desc, Date targetDate) {
		super();
		this.user = user;
		this.description = desc;
		this.targetDate = targetDate;
	}

	public long getId() {
		return id;
	}

	public void setId(long id) {
		this.id = id;
	}

	public User getUser() {
		return user;
	}

	public void setUser(User user) {
		this.user = user;
	}

	public String getDescription() {
		return description;
	}

	public void setDescription(String description) {
		this.description = description;
	}

	public Date getTargetDate() {
		return targetDate;
	}

	public void setTargetDate(Date targetDate) {
		this.targetDate = targetDate;
	}

	public Priority getPriority() {
		return priority;
	}

	public void setPriority(Priority priority) {
		this.priority = priority;
	}

	public Status getStatus() {
		return status;
	}

	public void setStatus(Status status) {
		this.status = status;
	}

	public Set<Tag> getTags() {
		return tags;
	}

	public void setTags(Set<Tag> tags) {
		this.tags = tags;
	}
}

package net.guides.springboot.todomanagement.repository;

import java.util.Optional;

import org.springframework.data.jpa.repository.JpaRepository;

import net.guides.springboot.todomanagement.model.Tag;

public interface TagRepository extends JpaRepository<Tag, Long> {
    Optional<Tag> findByName(String name);
}

package net.guides.springboot.todomanagement.service;

import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import net.guides.springboot.todomanagement.model.Tag;
import net.guides.springboot.todomanagement.repository.TagRepository;

@Service
public class TagService {

    @Autowired
    private TagRepository tagRepository;

    public List<Tag> findAll() {
        return tagRepository.findAll();
    }

    public Optional<Tag> findByName(String name) {
        return tagRepository.findByName(name);
    }

    public Tag createIfNotExists(String name) {
        if (name == null) return null;
        String n = name.trim();
        if (n.isEmpty()) return null;
        Optional<Tag> t = tagRepository.findByName(n);
        if (t.isPresent()) return t.get();
        Tag tag = new Tag(n);
        return tagRepository.save(tag);
    }

    public List<String> findAllNames() {
        return tagRepository.findAll().stream().map(Tag::getName).collect(Collectors.toList());
    }

    public void deleteById(Long id) {
        tagRepository.deleteById(id);
    }
}
